function AssignNonZerosToStorageUnits(data,node)
  (;Node) = data
  (;UnNode,UnPlant,xUnGC) = data

  #
  # Assign small non-zero capacity in last historical year for Battery
  #
  units_n=findall(UnNode[:] .== Node[node])
  units_p=findall(UnPlant[:] .== "Battery")
  units=intersect(units_n,units_p)
  if !isempty(units)
    for unit in units
      xUnGC[unit,Yr(2021)]=max(xUnGC[unit,Yr(2021)],1.0)
    end
  end

end

function ApplyAEOGrowthRate(data,node,plants)
  (;Node,Plant) = data
  (;UnNode,UnPlant,xUnGC) = data
  (;AEOGrowth,AEOTotal,E2020Total) = data

  years=collect(Yr(2022):Final)
  for plant in plants
    PlantName=Plant[plant]
    NodeName=Node[node]
    units_n=findall(UnNode[:] .== Node[node])
    units_p=findall(UnPlant[:] .== Plant[plant])
    units=intersect(units_n,units_p)
    if !isempty(units)
      for year in years
        @finite_math AEOGrowth[plant,year]=(AEOTotal[plant,year]-AEOTotal[plant,year-1])/AEOTotal[plant,year-1]
      end
      for year in years, unit in units
        xUnGC[unit,year]=xUnGC[unit,year-1]*(1+AEOGrowth[plant,year])
      end
      E2020Total[plant,first(years)-1]=sum(xUnGC[unit,first(years)-1] for unit in units)
      if E2020Total[plant,first(years)-1] > 0
        for year in years, unit in units
          xUnGC[unit,year]=xUnGC[unit,year-1]*(1+AEOGrowth[plant,year])
        end
      else
        @info "Error: AEO has capacity, but not ENERGY 2100 for for $PlantName in $NodeName"
      end
    else
      if sum(AEOTotal[plant,year] for year in years) > 0
        @info "Error: AEO has capacity, but no Units are defined for $PlantName in $NodeName"
      end
    end
  end
end

function RenewableCapacity(data,node)
  (;Areas,Node,Plant) = data
  (;Year,Years) = data
  (;UnNode,UnPlant,xUnGC) = data
  (;AEOTotal,E2020Total) = data

  #
  # Scale to AEO Totals
  #
  plants=Select(Plant,["Battery","Geothermal","Waste","Biomass","SolarPV","SolarThermal","OnshoreWind","OffshoreWind"])
  years=collect(Yr(2021):Final)
  for plant in plants
    PlantName=Plant[plant]
    NodeName=Node[node]
    units_n=findall(UnNode[:] .== Node[node])
    units_p=findall(UnPlant[:] .== Plant[plant])
    units=intersect(units_n,units_p)
    if !isempty(units)
      for year in years
        E2020Total[plant,year]=sum(xUnGC[unit,year] for unit in units)
      end
      for year in years
        if E2020Total[plant,year] > 0
          for unit in units
            @finite_math xUnGC[unit,year]=xUnGC[unit,year]*AEOTotal[plant,year]/E2020Total[plant,year]
          end
        else
          YearName=Year[year]
          @info "Error: AEO has capacity, but not ENERGY 2100 for for $PlantName in $NodeName in $YearName"
        end
      end
    else
      if sum(AEOTotal[plant,year] for year in years) > 0
        @info "Error: AEO has capacity, but no Units are defined for $PlantName in $NodeName"
      end
    end
  end

  #
  # Set Potential Capacity to Multiple of AEO Total
  #
  # for year in Years, area in Areas, plant in plants
  #   xGCPot[plant,node,area,year]=AEOTotal[plant,Yr(2050)]*NdArFr[node,area,year]*1.50
  #   if Plant[plant] == "Geothermal"
  #     xGCPot[plant,node,area,year]=AEOTotal[plant,Yr(2050)]*NdArFr[node,area,year]*1.10
  #   end
  # end

end

